            ) : (
              <ul>
                {exceptionFlows.map((ef: { id?: string; name?: string; trigger?: string; handling?: string }, i: number) => (
                  <li key={i}>
                    <strong>{ef.name || ef.id || `Exception ${i + 1}`}</strong>
                    {ef.trigger && <span>: Trigger: {ef.trigger}</span>}
                    {ef.handling && <Md text={ef.handling} />}
                  </li>
                ))}
              </ul>
            )}
          </CollapsibleSection>
